import{c as l,Q as i,j as r,g as e,n as t}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"出使德意志皇帝","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/114-出使德意志皇帝.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/114-出使德意志皇帝.md"}'),c={name:"research/machiavelli/machiavelli/diplomatic/lower/114-出使德意志皇帝.md"};function o(s,a,n,m,d,p){return i(),r("div",null,[...a[0]||(a[0]=[e("h1",{id:"出使德意志皇帝",tabindex:"-1"},[t("出使德意志皇帝 "),e("a",{class:"header-anchor",href:"#出使德意志皇帝","aria-label":'Permalink to "出使德意志皇帝"'},"​")],-1),e("p",null,"出使德意志皇帝 意志来说就是一种无上的光荣,对皇帝来说也非常难能可贵。如果皇帝得 到另外一个势力的支持,那么德意志就有理由放弃对皇帝的支持。如果皇 帝因为第三方势力的支持,实力与日俱增,那么就可能引起德意志对皇帝 的不信任。相比之下,德意志自己给皇帝提供或多或少的支持,就是更小 的事情了。我会保持沉默,等待时间的流逝。如果保罗大人(他现在博尔 扎诺)五六日内还没有到这里来,那么我就会去找他。不过,我实在不知 道如何避免谈判破裂。因为,诸位大人虽然自称怀抱着最大的敬意,但对 缔结协议的事,却如此精心经营,以至于迟迟不能达成共识。而皇帝总是 资金不足,某些时候更是特别紧缺。如果诸位大人没有抓住他资金最为紧 缺的时机,那么等到他过了这个勉强愿意接受的时候,他就会索要更多金 钱。他现在十有八九正处于这个最为窘迫的时候,按照诸位大人的推测, 他可能无法实现进入意大利的计划。不过这样的情况也可能发生:他可能 会认为,在尘埃落定之前,还是有必要维持他的部队,那么他的兵力可能 很快又会增强。但是如前所述,从目前的情况看来,这样突然增强兵力不 太可能。这个判断促使我在之前的信中写道:没有人能够断定他不会进入 意大利。因为德意志只要下定决心,就能帮助他实现计划。另一方面,也 没有人能够断定他会进入意大利。因为德意志从未对这场战争表示支持, 而且到目前为止也没有明显的证据,表明德意志已经改变主意。而且正如 我前面所说,也没有证据表明,蒂罗尔可以独力支撑。所以,我怀着最大 的敬意,冒险建议诸位大人采取以下两种方案之一。或者是按照皇帝的要 求,与其签订协议。这可能是最佳方案,因为皇帝只要还健在,就总会想 方设法进入意大利。如果不是今年,就可能是明年;如果不是独自前往, 就可能是与其他势力联合。或者是等到皇帝真的进入意大利再说。这样 的话,就必须假定:皇帝总是缺钱,诸位大人总是可以来得及与他签订 协议。即使诸位大人这么做,可能要冒着多花钱的风险。诸位大人必须考 虑,哪种方案更为稳妥,然后依赖上帝的指引,做出决定。因为当人类面对 这种重大事件时,他们总是机关算尽、步步为营,但结果却可能自投罗网。",-1),e("p",null,"Opere complete di Niccolo Machiavelli",-1)])])}const f=l(c,[["render",o]]);export{h as __pageData,f as default};
